               <span className="w-1.5 h-1.5 rounded-full bg-[#ED1C24] dark:bg-[#FFC20E] animate-ping" />
               <span>ನೋಂದಣಿ ಐಡಿ: {profileData.registration_id}</span>
             </div>
           </div>
         </header>

